async function ensureOffscreen(){(await chrome.runtime.getContexts({contextTypes:["OFFSCREEN_DOCUMENT"]})).length>0||await chrome.offscreen.createDocument({url:"offscreen.html",reasons:["WORKERS"],justification:"ML model inference with WebGPU"})}ensureOffscreen();let runCounter=0;chrome.runtime.onMessage.addListener((e,n,r)=>{if("SAVE_METRICS"===e.type){"json"===e.format&&runCounter++;const n=`data:${"json"===e.format?"application/json":"text/csv"};base64,${btoa(unescape(encodeURIComponent(e.data)))}`,o=`vit-gpt2-benchmark-run${runCounter}.${e.format}`;return chrome.downloads.download({url:n,filename:`gif-benchmarks/${o}`,conflictAction:"overwrite",saveAs:!1},()=>{r({ok:!0,runId:runCounter})}),!0}if("DESCRIBE_GIF"===e.type&&"offscreen"!==e.target)return console.log("[background] Forwarding DESCRIBE_GIF to offscreen"),ensureOffscreen().then(()=>chrome.runtime.sendMessage({...e,target:"offscreen"})).then(e=>{console.log("[background] Got response from offscreen:",e),r(e)}).catch(e=>{console.error("[background] Error:",e),r({error:e.message})}),!0});